mapper.sql:
SELECT T.ID, T.USER_ID, T.SESSION_ID, T.GOODS_ID, T.GOODS_SN, T.PRODUCT_ID, T.GOODS_NAME, T.MARKET_PRICE, T.RETAIL_PRICE, T.NUMBER, T.GOODS_SPECIFITION_NAME_VALUE, T.GOODS_SPECIFITION_IDS, T.CHECKED, T.LIST_PIC_URL, U.NICKNAME FROM MALL_CART T LEFT JOIN WX_USER U ON T.USER_ID = U.ID WHERE 1=1
AND T.ID = #{params.id}
AND T.NAME LIKE '%${params.name}%'

mapper.update:
update mall_cart
set `checked` = #{isChecked}
where product_id in

    #{productId}

and user_id = #{userId}

mapper.delete:
delete from mall_cart where product_id in

    #{id}

and user_id = #{userId}

mapper.select:
select a.*,
b.list_pic_url,
c.retail_price as retail_product_price
from mall_cart a
left join mall_goods b on a.goods_id = b.id
left join mall_product c on c.goods_id = a.goods_id and c.id = a.product_id
where 1 = 1

    AND a.user_id = #{userId}


    AND a.goods_id = #{goodsId}


    AND a.product_id = #{productId}


    AND a.checked = #{checked}



        order by ${sidx} ${order}


        order by a.id desc



    limit #{offset}, #{limit}
